import { createContext, type PropsWithChildren, useRef } from 'react';

import type { FilterSegment as QueryFilterSegment } from '@dynatrace-sdk/client-query';

import { createStore } from '../../../../core/store/store.js';

/**
 * @internal
 */
export const SegmentsContext = createContext(
  createStore<QueryFilterSegment[]>([]),
);

/**
 * @public
 */
export const SegmentsProvider = (
  props: PropsWithChildren<{ defaultSegments?: QueryFilterSegment[] }>,
) => {
  const { children, defaultSegments = [] } = props;

  const segmentsStoreRef = useRef(
    createStore<QueryFilterSegment[]>(defaultSegments),
  );

  return (
    <SegmentsContext.Provider value={segmentsStoreRef.current}>
      {children}
    </SegmentsContext.Provider>
  );
};
